function  [e2,x2,y2,z2] = fBin3DEfld(e1,x,y,z,binAry)%% function bin 3d e-field%% [e2,x2,y2,z2] = fPad3DEfld(e1,x1,y1,z1,dim2,varargin)%% e2: 3d array of e-filed (y,x,z)% x2: new x % y2: new y % z2: new z%% e1: 3d array of e-filed (y,x,z)% x1: x % y1: y % z1: z% dim2: desired dimension [y,x,z]% offset: [y,x,z]%% Written by Kei Nakamura%% 2018/12/6: created%%% main body% paddingsz1 = size(e1); % size 1modY = mod(sz1(1),binAry(1));   % see if we need to padmodX = mod(sz1(2),binAry(2));modZ = mod(sz1(3),binAry(3));if(modY+modX+modZ)~=0    [e1,x,y,z] = fPad3DEfld(e1,x,y,z,[sz1(1)+modY sz1(2)+modX sz1(3)+modZ]);endsz2 = sz1./binAry;e2XZ = zeros([sz2(1),sz1(2:3)]);e2Z = zeros([sz2(1:2),sz1(3)]);e2 = zeros(sz2);y2 = zeros(sz2(1),1);x2 = zeros(sz2(2),1);z2 = zeros(sz2(3),1);% bin yfor ii = 1:binAry(1)    e2XZ = e2XZ + e1(ii:binAry(1):end,:,:);    y2 = y2 + y(ii:binAry(1):end);endy2 = y2/binAry(1);% bin xfor ii = 1:binAry(2)    e2Z = e2Z + e2XZ(:,ii:binAry(2):end,:);    x2 = x2 + x(ii:binAry(2):end);endx2 = x2/binAry(2);% bin zfor ii = 1:binAry(3)    e2 = e2 + e2Z(:,:,ii:binAry(3):end);    z2 = z2 + z(ii:binAry(3):end);endz2 = z2/binAry(3);
